document.addEventListener("DOMContentLoaded",function(){const t=document.querySelector(".nav-toggle"),n=document.querySelector(".nav-menu");t&&n&&t.addEventListener("click",function(){const e=this.getAttribute("aria-expanded")==="true";this.setAttribute("aria-expanded",!e),n.classList.toggle("is-open")}),document.querySelectorAll('a[href^="#"]').forEach(e=>{e.addEventListener("click",function(e){const t=this.getAttribute("href");if(!t||!t.startsWith("#")||t==="#"||t.length<2)return;e.preventDefault();const n=document.querySelector(t);n&&n.scrollIntoView({behavior:"smooth"})})});const e=document.querySelector(".site-header");e&&window.addEventListener("scroll",function(){window.scrollY>10?e.classList.add("is-scrolled"):e.classList.remove("is-scrolled")})})